13→/**
14→ * Extracts the earliest and latest top-level `timestamp` values from JSONL content.
15→ * Returns [earliest, latest] as ISO strings without trailing "Z", or [fallback, fallback]
16→ * if no valid timestamps are found.
17→ */
18→export function extractTimestampRange(
19→	content: string,
20→	fallback: string,
21→): [string, string] {
22→	const lines = content.split("\n");
23→	let earliest: number | undefined;
24→	let latest: number | undefined;
25→
26→	for (const line of lines) {
27→		const trimmed = line.trim();
28→		if (!trimmed) continue;
29→
30→		const tsMatch = trimmed.match(/"timestamp"\s*:\s*"([^"]+)"/);
31→		if (!tsMatch?.[1]) continue;
32→
33→		const ms = Date.parse(tsMatch[1]);
34→		if (Number.isNaN(ms)) continue;
35→
36→		if (earliest === undefined || ms < earliest) earliest = ms;
37→		if (latest === undefined || ms > latest) latest = ms;
38→	}
39→
40→	if (earliest === undefined || latest === undefined) {
41→		return [fallback, fallback];
42→	}
43→
44→	const fmt = (ms: number) => new Date(ms).toISOString().replace("Z", "");
45→	return [fmt(earliest), fmt(latest)];
46→}
47→
48→export function buildSessionRow(
49→	input: IngestSessionInput,
50→	context: IngestContext,
51→): RudelClaudeSessionsRow {
52→	const now = new Date().toISOString().replace("Z", "");
53→
54→	const subagents: Record<string, string> = {};
55→	if (input.subagents) {
56→		for (const sub of input.subagents) {
57→			subagents[sub.agentId] = sub.content;
58→		}
59→	}
60→
61→	const [sessionDate, lastInteractionDate] = extractTimestampRange(
62→		input.content,
63→		now,
64→	);
65→
66→	return {
67→		session_date: sessionDate,
68→		last_interaction_date: lastInteractionDate,
69→		session_id: input.sessionId,
70→		organization_id: context.organizationId,
71→		project_path: input.projectPath,
72→		repository: input.repository ?? null,
73→		content: input.content,
74→		subagents,
75→		skills: [],
76→		slash_commands: [],
77→		subagent_types: [],
78→		ingested_at: now,
79→		user_id: context.userId,
80→		git_branch: input.gitBranch ?? null,
81→		git_sha: input.gitSha ?? null,
82→		input_tokens: "0",
83→		output_tokens: "0",
84→		cache_read_input_tokens: "0",
85→		cache_creation_input_tokens: "0",
86→		total_tokens: "0",
87→		tag: input.tag ?? null,
88→	};
89→}
90→
91→export async function ingestSession(
92→	ingestor: Ingestor,
93→	input: IngestSessionInput,
94→	context: IngestContext,
95→): Promise<void> {
96→	const row = buildSessionRow(input, context);
97→	await ingestRudelClaudeSessions(ingestor, [row]);
98→}
