189→// ClickHouse Cloud's @clickhouse/client insert() silently drops data.
190→// Wrap the executor to use execute() with FORMAT JSONEachRow instead.
191→// async_insert=0 forces synchronous insert so data is immediately queryable.
192→const executor: typeof baseExecutor = {
193→	...baseExecutor,
194→	async insert(params) {
195→		const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
196→		await baseExecutor.execute(
197→			`INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
198→		);
199→	},
200→};
