202→afterAll(() => {
203→	// Fire-and-forget: ClickHouse Cloud DELETE mutations are slow
204→	executor
205→		.execute(`DELETE FROM rudel.claude_sessions WHERE session_id = '${testId}'`)
206→		.catch(() => {});
207→});
