209→async function waitForRow(
210→	sessionId: string,
211→	timeoutMs = 30000,
212→	intervalMs = 2000,
213→): Promise<
214→	Array<{
215→		session_id: string;
216→		project_path: string;
217→		repository: string;
218→		tag: string;
219→		user_id: string;
220→		organization_id: string;
221→	}>
222→> {
223→	const start = Date.now();
224→	while (Date.now() - start < timeoutMs) {
225→		try {
226→			const results = await executor.query<{
227→				session_id: string;
228→				project_path: string;
229→				repository: string;
